import{_ as o,o as i,c as t,a2 as a}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Epic 17: Desktop App Shell","description":"","frontmatter":{},"headers":[],"relativePath":"epics/desktop.md","filePath":"epics/desktop.md"}'),s={name:"epics/desktop.md"};function n(r,e,l,c,d,p){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="epic-17-desktop-app-shell" tabindex="-1">Epic 17: Desktop App Shell <a class="header-anchor" href="#epic-17-desktop-app-shell" aria-label="Permalink to &quot;Epic 17: Desktop App Shell&quot;">​</a></h1><blockquote><p>Tauri-based desktop shell app that loads a user&#39;s self-hosted Sovereign instance in a WebView — macOS first, Windows and Linux follow.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>📋 Planned</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Sovereign&#39;s post-v1 native client strategy uses the same model for mobile and desktop: a minimal shell where the user enters their instance URL on first launch and the shell loads it in a WebView. All functionality is served by the user&#39;s own instance — the shell provides only the native wrapper.</p><p>The desktop shell (<code>sovereign-desktop</code>, separate repository) is built with Tauri 2.x: TypeScript for all shell logic, system WebView on each platform (WKWebView on macOS, WebView2 on Windows, WebKitGTK on Linux), ~5 MB binary. This mirrors the Capacitor choice for mobile: minimal shell, web content does the work, native capabilities added via Tauri plugins as needed.</p><p>Plugin developers are unaffected — <code>sdk.device.*</code> gains a <code>&quot;desktop&quot;</code> environment check internally; no plugin code changes required.</p><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="📋-17-1-—-sovereign-desktop-—-tauri-shell-scaffold-macos-first" tabindex="-1">📋 17.1 — sovereign-desktop — Tauri shell scaffold (macOS-first) <a class="header-anchor" href="#📋-17-1-—-sovereign-desktop-—-tauri-shell-scaffold-macos-first" aria-label="Permalink to &quot;📋 17.1 — sovereign-desktop — Tauri shell scaffold (macOS-first)&quot;">​</a></h4><p><strong>Goal:</strong> Bootstrap <code>sovereign-desktop</code> with a working Tauri 2.x shell — first-launch instance URL onboarding, URL validation against <code>/api/admin/health</code>, persistent storage, WebView loading, multiple instance support — and a GitHub Actions workflow producing a signed/notarized macOS <code>.dmg</code> plus unsigned Windows and Linux artifacts on every tagged release.</p><p><strong>Deliverables:</strong></p><ul><li><code>sovereign-desktop/</code> (new repo): <ul><li><code>src-tauri/</code> — Tauri 2 scaffold (<code>tauri.conf.json</code>, <code>Cargo.toml</code>, <code>src/lib.rs</code>)</li><li><code>src/onboarding.ts</code> — first-launch URL entry + <code>/api/admin/health</code> validation</li><li><code>src/store.ts</code> — instance URL list via <code>@tauri-apps/plugin-store</code></li><li><code>src/main.ts</code> — boot: check stored URLs → onboarding or load WebView</li><li><code>index.html</code> — onboarding UI (local HTML rendered on first launch)</li><li><code>.github/workflows/release.yml</code> — builds <code>.dmg</code> (macOS, signed + notarized), <code>.exe</code>/<code>.msi</code> (Windows), <code>.AppImage</code>/<code>.deb</code> (Linux) on <code>v*</code> tags</li></ul></li><li><code>packages/sdk</code> patch — add <code>&quot;desktop&quot;</code> environment to <code>sdk.device.*</code> routing; semver patch bump</li></ul><p><strong>macOS CI secrets required:</strong> <code>APPLE_CERTIFICATE</code>, <code>APPLE_CERTIFICATE_PASSWORD</code>, <code>APPLE_SIGNING_IDENTITY</code>, <code>APPLE_ID</code>, <code>APPLE_PASSWORD</code>.</p><p><strong>SRS reference:</strong> §3.19, §3.12 (mobile; same model)</p><p><strong>Review checklist:</strong></p><ul><li><code>cargo tauri dev</code> opens the app; onboarding screen shown on first launch</li><li>Valid instance URL loads the instance in the WebView and persists across restarts</li><li>Invalid URL shows an inline error; app does not crash</li><li>Multiple instance entries can be added and switched between</li><li><code>cargo tauri build</code> produces a <code>.app</code> bundle and <code>.dmg</code></li><li>GitHub Actions <code>release.yml</code> runs on a <code>v0.1.0</code> tag and attaches all artifacts</li><li><code>pnpm test</code> passes in <code>packages/sdk</code> after the <code>&quot;desktop&quot;</code> environment addition</li></ul><h4 id="📋-17-2-—-system-tray-and-os-notifications" tabindex="-1">📋 17.2 — System tray and OS notifications <a class="header-anchor" href="#📋-17-2-—-system-tray-and-os-notifications" aria-label="Permalink to &quot;📋 17.2 — System tray and OS notifications&quot;">​</a></h4><p><strong>Goal:</strong> Add persistent system presence via a menu bar / system tray icon and OS-level notifications so users receive Sovereign alerts even when the main window is closed.</p><p><strong>Deliverables:</strong></p><ul><li><code>tauri-plugin-system-tray</code> integration — tray icon with a context menu: Open, Switch Instance (submenu), Quit</li><li><code>tauri-plugin-notification</code> integration — <code>sdk.device.notify()</code> routes to native OS notifications in the <code>&quot;desktop&quot;</code> environment (falls back to Web Notifications API in browser)</li><li><code>packages/sdk</code> minor bump — <code>sdk.device.notify()</code> desktop tier implementation</li></ul><p><strong>SRS reference:</strong> §3.19</p><p><strong>Review checklist:</strong></p><ul><li>App shows a tray icon on macOS menu bar after launch</li><li>Closing the main window does not quit the app; tray icon remains</li><li>Context menu &quot;Open&quot; restores the window</li><li><code>sdk.device.notify({ title, body })</code> triggers a native macOS notification</li><li>Web Notifications API fallback still works in the browser</li></ul><h4 id="📋-17-3-—-deep-link-scheme-sovereign" tabindex="-1">📋 17.3 — Deep link scheme (<code>sovereign://</code>) <a class="header-anchor" href="#📋-17-3-—-deep-link-scheme-sovereign" aria-label="Permalink to &quot;📋 17.3 — Deep link scheme (`sovereign://`)&quot;">​</a></h4><p><strong>Goal:</strong> Register a <code>sovereign://</code> URL scheme so links in emails and browsers open the desktop app and navigate to the correct instance and path.</p><p><strong>Deliverables:</strong></p><ul><li><code>tauri-plugin-deep-link</code> integration — registers <code>sovereign://</code> on macOS, Windows, and Linux</li><li>URL parsing: <code>sovereign://&lt;instance-host&gt;/&lt;path&gt;</code> → validate instance is in stored list → load WebView at <code>https://&lt;instance-host&gt;/&lt;path&gt;</code></li><li>Unknown instance → prompt user to add it via onboarding flow</li></ul><p><strong>SRS reference:</strong> §3.19</p><p><strong>Review checklist:</strong></p><ul><li>Clicking a <code>sovereign://my.instance.example/plugins/console</code> link opens the app and navigates to <code>/plugins/console</code> on the matching instance</li><li>Unknown instance shows the add-instance prompt rather than crashing</li><li>Scheme registered correctly on macOS (<code>LSApplicationQueriesSchemes</code> in <code>Info.plist</code>)</li></ul><h4 id="📋-17-4-—-keychain-credential-storage" tabindex="-1">📋 17.4 — Keychain credential storage <a class="header-anchor" href="#📋-17-4-—-keychain-credential-storage" aria-label="Permalink to &quot;📋 17.4 — Keychain credential storage&quot;">​</a></h4><p><strong>Goal:</strong> Store the user&#39;s session token in the OS keychain (macOS Keychain, Windows Credential Manager, Linux Secret Service) so it survives app restarts without relying on WebView cookie persistence.</p><p><strong>Deliverables:</strong></p><ul><li><code>tauri-plugin-stronghold</code> or <code>tauri-plugin-keychain</code> integration — write/read session token per instance</li><li>Cleared on &quot;Sign out&quot; action and on instance removal</li><li><code>packages/sdk</code> patch — <code>sdk.device.secureStore.*</code> surface (set / get / delete)</li></ul><p><strong>SRS reference:</strong> §3.19</p><p><strong>Review checklist:</strong></p><ul><li>Session token survives an app restart without re-authentication</li><li>Removing an instance clears its stored token from the keychain</li><li><code>sdk.device.secureStore.set/get/delete</code> round-trips correctly in the desktop env</li></ul><h4 id="📋-17-5-—-auto-updater" tabindex="-1">📋 17.5 — Auto-updater <a class="header-anchor" href="#📋-17-5-—-auto-updater" aria-label="Permalink to &quot;📋 17.5 — Auto-updater&quot;">​</a></h4><p><strong>Goal:</strong> Allow the app to check for and apply updates in-app so users are never silently running a stale binary.</p><p><strong>Deliverables:</strong></p><ul><li><code>tauri-plugin-updater</code> integration — checks GitHub Releases for a new version on startup (configurable interval)</li><li>Update prompt UI: version number, changelog excerpt, &quot;Update now&quot; / &quot;Later&quot;</li><li>Background download + install on quit</li></ul><p><strong>SRS reference:</strong> §3.19</p><p><strong>Review checklist:</strong></p><ul><li>App checks for updates on launch and shows a banner when a newer version exists</li><li>&quot;Update now&quot; downloads and installs the update; app restarts to the new version</li><li>&quot;Later&quot; dismisses the banner until the next launch</li><li>No update available → no UI shown</li></ul><h4 id="📋-17-6-—-mac-app-store-distribution" tabindex="-1">📋 17.6 — Mac App Store distribution <a class="header-anchor" href="#📋-17-6-—-mac-app-store-distribution" aria-label="Permalink to &quot;📋 17.6 — Mac App Store distribution&quot;">​</a></h4><p><strong>Goal:</strong> Publish the macOS build to the Mac App Store as an alternative to direct download, reaching users who prefer sandboxed App Store apps.</p><p><strong>Deliverables:</strong></p><ul><li>Tauri build configured for Mac App Store sandboxing (<code>com.apple.security.*</code> entitlements for WebView network access, keychain, notifications)</li><li><code>MAS_CERTIFICATE</code>, <code>MAS_PROVISIONING_PROFILE</code> CI secrets and signing flow</li><li>App Store Connect listing (screenshots, description, privacy nutrition labels)</li><li>Separate GitHub Actions job: <code>release-mas.yml</code> — builds MAS variant and submits via <code>xcrun altool</code> / <code>notarytool</code></li></ul><p><strong>SRS reference:</strong> §3.19</p><p><strong>Review checklist:</strong></p><ul><li>MAS build passes <code>codesign --verify</code> with sandbox entitlements</li><li>Submitted build passes App Review (no private API usage)</li><li>App Store listing shows correct screenshots and privacy labels</li></ul><h2 id="related-rfcs" tabindex="-1">Related RFCs <a class="header-anchor" href="#related-rfcs" aria-label="Permalink to &quot;Related RFCs&quot;">​</a></h2><ul><li><a href="./../rfcs/0038-desktop-app-shell.html">RFC 0038 — Desktop app shell (Tauri, macOS-first)</a></li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../../CLAUDE.html">CLAUDE.md — Desktop app (post-v1 plan)</a></li><li><a href="./../sovereign-proposal-plan-srs.html">sovereign-proposal-plan-srs.md §3.12 and §3.19</a></li></ul><h2 id="cross-references" tabindex="-1">Cross-references <a class="header-anchor" href="#cross-references" aria-label="Permalink to &quot;Cross-references&quot;">​</a></h2><ul><li>Epic 3 (Plugins Runtime) — <code>sdk.device.*</code> in <code>packages/sdk</code>; desktop tier is a patch to the existing abstraction</li><li>Mobile (<code>sovereign-mobile</code>, post-v1) — same universal shell + instance URL model</li></ul>',58)])])}const g=o(s,[["render",n]]);export{h as __pageData,g as default};
